        IEnumerable<T> collection, Func<T, string?> formatter, string separator)
    {
        // Single-pass: format, trim, and collect non-empty items in one loop
        var items = new List<string>();
        foreach (var element in collection)
        {
            var formatted = formatter(element);
            if (formatted == null) continue;

            var trimmed = formatted.AsSpan().Trim();
            if (trimmed.Length > 0)
            {
                items.Add(trimmed.Length == formatted.Length ? formatted : trimmed.ToString());
            }
        }

        if (items.Count == 0)
