/// <summary>
/// Provides extension methods for transforming strings with transformer chains.
/// </summary>
public static class TransformExtensions
{
    /// <summary>
    /// Transforms a string using a single transformer (avoids params array allocation).
    /// </summary>
    public static string Transform(
        this string input, CultureInfo culture, IStringTransformer transformer) =>
        transformer.Transform(input);

    /// <summary>
    /// Transforms a string using the provided transformers, applied in order.
    /// </summary>
    /// <param name="input">The string to transform.</param>
    /// <param name="culture">The culture for culture-sensitive transformations.</param>
    /// <param name="transformers">One or more transformers to apply sequentially.</param>
    /// <returns>The transformed string.</returns>
    public static string Transform(
        this string input, CultureInfo culture, params IStringTransformer[] transformers)
    {
        var result = input;
        for (var i = 0; i < transformers.Length; i++)
        {
            result = transformers[i].Transform(result);
        }

        return result;
    }
}

